                // Capitalize the first letter
                result.append(Character.toUpperCase(currentChar));
            } else {
                // Check if current character is a letter and if it's not an exception word
                if (Character.isLetter(currentChar)) {
                    // Check if the current word is an exception word
                    boolean isExceptionWord = EXCEPTION_WORDS.contains(input.substring(i - 1, i + 1));
                    if (!isExceptionWord) {
                        result.append(Character.toUpperCase(currentChar));
                    } else {
                        result.append(currentChar);
                    }
                } else {
                    result.append(currentChar);
